import { describe, expect, it } from '@a0n/gnosis/test';
import {
  canonicalEscInput,
  computeEscCacheKey,
  decodeEscWasmSegment,
  encodeEscWasmSegment,
  EscMemoryTier,
  slicePackedKnot,
} from './edge-side-compute';
import { dnaToKnot } from '../runtime/packed-knot';

describe('edge-side-compute (ESC)', () => {
  it('slicePackedKnot preserves crossings and node ids', () => {
    const knot = dnaToKnot('ACGTACGT');
    const slice = slicePackedKnot(knot, 2, 6);
    expect(slice.crossingCount).toBe(4);
  });

  it('computeEscCacheKey is stable for identical inputs', () => {
    const knot = dnaToKnot('TT');
    const a = computeEscCacheKey({
      knotSlice: knot,
      entryCrossingIndex: 0,
      canonicalInput: canonicalEscInput({ n: 1 }),
      artifactFingerprint: 'abc',
      runtimeBindingHash: 'bind',
      policySalt: 'salt',
      handlerVersionParts: ['main', 'json-v1'],
    });
    const b = computeEscCacheKey({
      knotSlice: knot,
      entryCrossingIndex: 0,
      canonicalInput: canonicalEscInput({ n: 1 }),
      artifactFingerprint: 'abc',
      runtimeBindingHash: 'bind',
      policySalt: 'salt',
      handlerVersionParts: ['main', 'json-v1'],
    });
    expect(a).toBe(b);
  });

  it('computeEscCacheKey differs when entry index changes', () => {
    const knot = dnaToKnot('TT');
    const a = computeEscCacheKey({
      knotSlice: knot,
      entryCrossingIndex: 0,
      canonicalInput: canonicalEscInput(null),
      artifactFingerprint: 'x',
    });
    const b = computeEscCacheKey({
      knotSlice: knot,
      entryCrossingIndex: 1,
      canonicalInput: canonicalEscInput(null),
      artifactFingerprint: 'x',
    });
    expect(a).not.toBe(b);
  });

  it('round-trips EscWasmSegmentRecord', () => {
    const record = {
      version: 1 as const,
      artifactId: 'art',
      exportName: 'main',
      abi: 'json-v1',
      payload: { ok: true },
      logs: '',
    };
    const back = decodeEscWasmSegment(encodeEscWasmSegment(record));
    expect(back).toEqual(record);
  });

  it('EscMemoryTier stores and retrieves', async () => {
    const tier = new EscMemoryTier();
    const record = {
      version: 1 as const,
      artifactId: 'a',
      exportName: 'main',
      abi: 'json-v1',
      payload: 42,
      logs: '',
    };
    await tier.set('k1', record);
    expect(await tier.get('k1')).toEqual(record);
    expect(tier.size).toBe(1);
  });
});
